function GIcon({ name, size = 18, color = C.b4 }) {
  const d = GI_PATHS[name]
  if (!d) return null
  return (
    <svg width={size} height={size} viewBox="0 0 512 512"
      style={{ display: 'block', flexShrink: 0 }}>
      <path d={d} fill={color}/>
    </svg>
  )
}


// ═══════════════════════════════════════════════════════════════
// ORNAMENTAL CORNER (diamond with arms — carved metalwork look)
// ═══════════════════════════════════════════════════════════════
function CornerDeco({ style }) {
  return (
    <div style={{ position: 'absolute', width: 20, height: 20, zIndex: 20, ...style }}>
      <svg viewBox="0 0 20 20" style={{ overflow: 'visible' }}>
        {/* Arms */}
        <rect x="9" y="0"  width="2" height="6" fill={C.b4}/>
        <rect x="9" y="14" width="2" height="6" fill={C.b4}/>
        <rect x="0"  y="9" width="6" height="2" fill={C.b4}/>
        <rect x="14" y="9" width="6" height="2" fill={C.b4}/>
        {/* Outer diamond */}
        <polygon points="10,4 16,10 10,16 4,10" fill={C.b4}/>
        {/* Inner fill (cut-out) */}
        <polygon points="10,7 13,10 10,13 7,10" fill={C.s0}/>
        {/* Bright center dot */}
        <rect x="9.5" y="9.5" width="1" height="1" fill={C.b5}/>
      </svg>
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════
// DIVIDER — ornamental horizontal rule
// ═══════════════════════════════════════════════════════════════
function Divider({ color = C.b2 }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '0 2px' }}>
      <div style={{ flex: 1, height: 1, background: `linear-gradient(90deg, transparent, ${color})` }}/>
      <svg width="8" height="8" viewBox="0 0 8 8" fill={color}>
        <polygon points="4,0 8,4 4,8 0,4"/>
      </svg>
      <div style={{ flex: 1, height: 1, background: `linear-gradient(90deg, ${color}, transparent)` }}/>
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════
// PANEL — core component with ornate border + stone texture
// ═══════════════════════════════════════════════════════════════
function Panel({ children, style = {}, active = false, flat = false }) {
  return (
    <div style={{
      position: 'relative',
      border: `2px solid ${active ? C.b5 : C.b4}`,
      boxShadow: FRAME(active),
      background: flat ? 'transparent'
        : `${TEX} repeat, linear-gradient(180deg, ${C.s1} 0%, ${C.s0} 100%)`,
      backgroundSize: '256px 256px, 100% 100%',
      ...style,
    }}>
      <CornerDeco style={{ top: -10, left: -10 }}/>
      <CornerDeco style={{ top: -10, right: -10 }}/>
      <CornerDeco style={{ bottom: -10, left: -10 }}/>
      <CornerDeco style={{ bottom: -10, right: -10 }}/>
      {children}
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════
// BUTTON — single source of truth for all button styles.
//
// variant: 'metal' | 'confirm' | 'dim' | 'danger' | 'default'
// size:    'sm' (compact, header) | 'md' (default) | 'lg'
// icon:    true → square, icon-only (uses height from size)
// fullWidth, style: layout only — never override visual props here.
//
// ALL visual properties (bg, border, shadow, color) live in `vars`.
// Per-site style overrides must only affect layout (width, margin, etc).
// ═══════════════════════════════════════════════════════════════
function Btn({ children, onClick, variant = 'default', size = 'md', icon = false, style = {}, fullWidth = false }) {
  const [pressed, setPressed] = useState(false)

  // ── Visual variants — never override these at call sites ──────
  const vars = {
    metal: {
      bg:     `linear-gradient(180deg, #332e24 0%, #201c14 60%, #2a2419 100%)`,
      border: `1px solid ${C.b3}`,
      borderB:`1px solid ${C.b2}`,
      shadow: `inset 0 1px 0 rgba(230,190,90,0.28), inset 0 -1px 0 rgba(0,0,0,0.6), inset 1px 0 0 rgba(200,160,60,0.08), 0 0 0 1px rgba(0,0,0,0.5)`,
      color:  C.t2,
    },
    confirm: {
      bg:     `linear-gradient(180deg, ${C.s3} 0%, ${C.s1} 100%)`,
      border: `2px solid ${C.b5}`,
      borderB:`3px solid ${C.b4}`,
      shadow: `inset 0 1px 0 rgba(240,216,144,0.2), 0 0 0 1px ${C.b1}, 0 0 8px rgba(200,146,26,0.2), 0 3px 10px rgba(0,0,0,0.7)`,
      color:  C.b6,
    },
    dim: {
      bg:     `linear-gradient(180deg, ${C.s1} 0%, ${C.s0} 100%)`,
      border: `2px solid ${C.b2}`,
      borderB:`3px solid ${C.b1}`,
      shadow: `inset 0 1px 0 rgba(255,255,255,0.04), 0 0 0 1px ${C.b0}, 0 2px 6px rgba(0,0,0,0.6)`,
      color:  C.t0,
    },
    danger: {
      bg:     `linear-gradient(180deg, ${C.red0} 0%, #200808 100%)`,
      border: `2px solid ${C.red1}`,
      borderB:`3px solid ${C.red2}`,
      shadow: `inset 0 1px 0 rgba(200,80,80,0.1), 0 0 0 1px ${C.b0}, 0 3px 10px rgba(0,0,0,0.7)`,
      color:  C.red2,
    },
    default: {
      bg:     `linear-gradient(180deg, ${C.s2} 0%, ${C.s0} 100%)`,
      border: `2px solid ${C.b4}`,
      borderB:`3px solid ${C.b3}`,
      shadow: `inset 0 1px 0 rgba(240,200,100,0.15), inset 0 -1px 0 rgba(0,0,0,0.5), 0 0 0 1px ${C.b1}, 0 3px 10px rgba(0,0,0,0.7)`,
      color:  C.t3,
    },
  }

  // ── Size tokens — controls padding, height, font ──────────────
  const sizes = {
    sm: { height: 30, padding: '0 12px', fontSize: 8,  letterSpacing: '0.12em', gap: 6 },
    md: { height: 36, padding: '0 18px', fontSize: 10, letterSpacing: '0.15em', gap: 8 },
    lg: { height: 44, padding: '0 24px', fontSize: 11, letterSpacing: '0.15em', gap: 9 },
  }

  const v = vars[variant] || vars.default
  const s = sizes[size] || sizes.md
  const h = s.height
  // Compute width once — icon always wins; fullWidth overrides only for non-icon
  const w = fullWidth ? '100%' : icon ? h : 'auto'

  return (
    <button
      onClick={onClick}
      onMouseDown={() => setPressed(true)}
      onMouseUp={() => setPressed(false)}
      onMouseLeave={() => setPressed(false)}
      style={{
        // Visual — from variant only
        background:    v.bg,
        border:        v.border,
        borderBottom:  pressed ? v.border : v.borderB,
        boxShadow:     v.shadow,
        color:         v.color,
        // Typography — from size only
        fontFamily:    F.ui,
        fontSize:      s.fontSize,
        letterSpacing: s.letterSpacing,
        textTransform: 'uppercase',
        // Layout — fully resolved, no spread overrides
        height:        h,
        width:         w,
        minWidth:      w,   // prevent flex from squishing the square
        padding:       icon ? 0 : s.padding,
        gap:           s.gap,
        boxSizing:     'border-box',
        // Always
        cursor:       'pointer',
        display:      'flex',
        alignItems:   'center',
        justifyContent:'center',
        flexShrink:   0,
        flexGrow:     0,
        alignSelf:    'center',
        transform:    pressed ? 'translateY(1px)' : 'none',
        transition:   'transform 0.08s',
        // Layout-only overrides from call site (margin, maxWidth, opacity, etc)
        ...style,
      }}
    >
      {children}
    </button>
  )
}

// ═══════════════════════════════════════════════════════════════
// PANEL TITLE BAR (matches reference panel header style)
// ═══════════════════════════════════════════════════════════════
function PanelTitle({ children, right }) {
  return (
    <>
      <div style={{
        padding: '10px 18px',
        borderBottom: `1px solid ${C.b2}`,
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        ...ST('raised'),
      }}>
        <span style={{ fontFamily: F.ui, fontSize: 12, letterSpacing: '0.2em', color: C.t3, textTransform: 'uppercase' }}>
          {children}
        </span>
        {right}
      </div>
      <Divider color={C.b3}/>
    </>
  )
}

// ═══════════════════════════════════════════════════════════════
// RICH TEXT RENDERER — **bold**, [n] citations
// ═══════════════════════════════════════════════════════════════
function Render({ text, sources = [] }) {
  return (
    <div style={{ fontFamily: F.body, fontSize: 15, lineHeight: 1.5, color: C.t2 }}>
      {text.split('\n\n').map((para, pi) => (
        <p key={pi} style={{ margin: pi > 0 ? '10px 0 0' : 0 }}>
          {para.split(/(\*\*[^*]+\*\*|\[\d+\])/).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**'))
              return <strong key={i} style={{ color: C.t3, fontWeight: 600 }}>{part.slice(2, -2)}</strong>
            const m = part.match(/^\[(\d+)\]$/)
            if (m) {
              const src = sources.find(s => s.index === +m[1])
              return (
                <a key={i} href={src?.url || '#'} target="_blank" rel="noopener noreferrer"
                  title={src?.title}
                  style={{
                    fontFamily: F.ui, fontSize: 9, color: C.b5,
                    verticalAlign: 'super', lineHeight: 0,
                    textDecoration: 'none', letterSpacing: '0.05em', padding: '0 2px',
                  }}>
                  [{m[1]}]
                </a>
              )
            }
            return <span key={i}>{part}</span>
          })}
        </p>
      ))}
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════
// SOURCES FOOTER
// ═══════════════════════════════════════════════════════════════
function SourcesFooter({ sources }) {
  const [open, setOpen] = useState(true)
  if (!sources?.length) return null
  return (
    <div style={{ marginTop: 12, paddingTop: 10, borderTop: `1px solid ${C.b1}` }}>
      <button onClick={() => setOpen(o => !o)} style={{
        background: 'none', border: 'none', cursor: 'pointer', padding: 0,
        display: 'flex', alignItems: 'center', gap: 7,
        fontFamily: F.ui, fontSize: 9, letterSpacing: '0.12em',
        color: C.t0, textTransform: 'uppercase',
      }}>
        <Ico name="search" size={11} color={C.t0}/>
        {sources.length} {sources.length === 1 ? 'Source' : 'Sources'}&ensp;{open ? '▲' : '▼'}
      </button>
      {open && (
        <div style={{ marginTop: 8, display: 'flex', flexDirection: 'column', gap: 3 }}>
          {sources.map(src => (
            <a key={src.index} href={src.url} target="_blank" rel="noopener noreferrer"
              style={{
                display: 'flex', alignItems: 'flex-start', gap: 8,
                padding: '6px 10px',
                background: `${TEX} repeat, ${C.s2}`,
                backgroundSize: '256px 256px, auto',
                border: `1px solid ${C.b1}`,
                borderLeft: `3px solid ${C.b3}`,
                textDecoration: 'none',
              }}>
              <span style={{ fontFamily: F.ui, fontSize: 9, color: C.b5, flexShrink: 0, marginTop: 3, letterSpacing: '0.05em' }}>
                [{src.index}]
              </span>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontFamily: F.body, fontSize: 14, color: C.t1, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                  {src.title}
                </div>
                <div style={{ fontFamily: F.ui, fontSize: 9, color: C.t0, letterSpacing: '0.06em' }}>{src.domain}</div>
              </div>
            </a>
          ))}
        </div>
      )}
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════
// MEMORY PROPOSAL TOAST
// ═══════════════════════════════════════════════════════════════
function ProposalToast({ proposal, onAccept, onDismiss }) {
  return (
    <div className="lk-fade" style={{
      marginTop: 10,
      border: `1px solid ${C.b2}`,
      borderLeft: `3px solid ${C.b4}`,
      background: `${TEX} repeat, linear-gradient(90deg, ${C.s2} 0%, ${C.s1} 100%)`,
      backgroundSize: '256px 256px, 100% 100%',
      padding: '10px 14px',
      display: 'flex', alignItems: 'flex-start', gap: 10,
    }}>
      <Ico name="quill" size={14} color={C.b4} style={{ flexShrink: 0, marginTop: 3 }}/>
      <div style={{ flex: 1 }}>
        <div style={{ fontFamily: F.ui, fontSize: 8, color: C.b4, letterSpacing: '0.15em', marginBottom: 5, textTransform: 'uppercase' }}>
          Memory Proposal
        </div>
        <div style={{ fontFamily: F.body, fontSize: 14, color: C.t1, lineHeight: 1.5 }}>
          {proposal.content}
        </div>
      </div>
      <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
        <Btn variant="confirm" onClick={onAccept} size="sm">
          <Ico name="check" size={10} color={C.b6}/>Accept
        </Btn>
        <Btn variant="dim" onClick={onDismiss} size="sm">
          Skip
        </Btn>
      </div>
    </div>
  )
}

// ═══════════════════════════════════════════════════════════════
// MEMORY CATEGORY METADATA (module-level)
// ═══════════════════════════════════════════════════════════════
const CAT_META = {
  quest:     { label: 'Quests',     icon: 'map',      color: '#c8921a' },
  character: { label: 'Character',  icon: 'shield',   color: '#7ab8d8' },
  location:  { label: 'Locations',  icon: 'location', color: '#8ab860' },
  choice:    { label: 'Choices',    icon: 'choice',   color: '#b880d8' },
  note:      { label: 'Notes',      icon: 'note',     color: '#a09c90' },
}

// ═══════════════════════════════════════════════════════════════
// MEMORY SHEET (bottom tray, like PlaythroughSheet)
// ═══════════════════════════════════════════════════════════════
function MemorySheet({ playthrough, onClose }) {
  const grouped = Object.fromEntries(Object.keys(CAT_META).map(k => [k, []]))
  playthrough.memory.forEach(m => { if (grouped[m.cat]) grouped[m.cat].push(m) })

  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 50,
      background: 'rgba(7,6,4,0.85)',
      display: 'flex', flexDirection: 'column', justifyContent: 'flex-end',
    }} onClick={onClose}>
      <div className="lk-slideup" onClick={e => e.stopPropagation()} style={{
        ...ST('raised'),
        borderTop: `2px solid ${C.b4}`,
        boxShadow: `0 -8px 40px rgba(0,0,0,0.9), 0 0 16px rgba(200,146,26,0.18)`,
        maxHeight: '65vh', overflowY: 'auto',
        paddingBottom: 20,
      }}>
        <PanelTitle right={
          <Btn variant="metal" size="sm" icon onClick={onClose}><Ico name="x" size={12} color={C.t1}/></Btn>
        }>
          <Ico name="book" size={14} color={C.b4}/>&ensp;Playthrough Memory
        </PanelTitle>

        <div style={{ padding: '14px 16px 0' }}>
          {Object.entries(CAT_META).map(([cat, meta]) => {
            const items = grouped[cat]
            if (!items?.length) return null
            return (
              <div key={cat} style={{ marginBottom: 18 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 7, marginBottom: 8 }}>
                  <Ico name={meta.icon} size={11} color={meta.color}/>
                  <span style={{ fontFamily: F.ui, fontSize: 9, color: meta.color, letterSpacing: '0.12em', textTransform: 'uppercase' }}>
                    {meta.label}
                  </span>
                </div>
                {items.map(m => (
                  <div key={m.id} style={{
                    padding: '8px 12px', marginBottom: 5,
                    background: C.s2, border: `1px solid ${C.b1}`,
                    borderLeft: `3px solid ${meta.color}`,
                    fontFamily: F.body, fontSize: 14, color: C.t1, lineHeight: 1.5,
                  }}>
                    {m.content}
                  </div>
                ))}
              </div>
            )
          })}
        </div>

        <div style={{ padding: '10px 16px 0' }}>
          <Btn variant="dim" fullWidth>
            <Ico name="plus" size={10} color={C.t0}/>&ensp;Add Memory
          </Btn>
        </div>
      </div>
    </div>
  )
}


// ═══════════════════════════════════════════════════════════════
// PLAYTHROUGH SHEET (mobile only — bottom drawer)
// ═══════════════════════════════════════════════════════════════
function PlaythroughSheet({ playthroughs, activeId, onSelect, onClose }) {
  return (
    <div style={{
      position: 'fixed', inset: 0, zIndex: 50,
      background: 'rgba(7,6,4,0.85)',
      display: 'flex', flexDirection: 'column', justifyContent: 'flex-end',
    }} onClick={onClose}>
      <div className="lk-slideup" onClick={e => e.stopPropagation()} style={{
        ...ST('raised'),
        borderTop: `2px solid ${C.b4}`,
        boxShadow: `0 -8px 40px rgba(0,0,0,0.9), 0 0 16px rgba(200,146,26,0.18)`,
        maxHeight: '70vh', overflowY: 'auto',
        paddingBottom: 24,
      }}>
        <PanelTitle right={
          <Btn variant="metal" size="sm" icon onClick={onClose}><Ico name="x" size={12} color={C.t1}/></Btn>
        }>
          Playthroughs
        </PanelTitle>
        <div style={{ padding: '8px 12px', display: 'flex', flexDirection: 'column', gap: 4 }}>
          {playthroughs.map(p => (
            <button key={p.id} onClick={() => { onSelect(p.id); onClose() }}
              style={{
                width: '100%', textAlign: 'left', cursor: 'pointer',
                padding: '12px 14px',
                background: activeId === p.id ? `${TEX} repeat, ${C.s3}` : 'transparent',
                backgroundSize: activeId === p.id ? '256px 256px, auto' : 'auto',
                border: 'none',
                borderLeft: `3px solid ${activeId === p.id ? C.b5 : C.b2}`,
              }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <Ico name="dragon" size={14} color={activeId === p.id ? C.b5 : C.t0}/>
                <div>
                  <div style={{ fontFamily: F.ui, fontSize: 10, color: activeId === p.id ? C.t3 : C.t0, letterSpacing: '0.1em' }}>
                    {p.name}
                  </div>
                  <div style={{ fontFamily: F.body, fontSize: 14, color: C.tDim, marginTop: 2 }}>
                    {p.game}
                  </div>
                </div>
              </div>
            </button>
          ))}
        </div>
      </div>
    </div>
  )
}

