// ═══════════════════════════════════════════════════════════════
// MOBILE HOOK
// ═══════════════════════════════════════════════════════════════
function useIsMobile() {
  const [mobile, setMobile] = useState(() => window.innerWidth < 680)
  useEffect(() => {
    const check = () => setMobile(window.innerWidth < 680)
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])
  return mobile
}

